`,path:"/books/all/2026-01-30-cleanarchi.html"},{slug:"2026-01-05-c",frontmatter:{title:"꿈에도 배울 줄 몰랐던 C 언어",bookName:"씹어먹는 C언어",author:"이재범",date:"2026-01-05T00:00:00.000Z",tags:["C"],thumbnail:"/images/2026-01-05-c/thumbnail.png"},excerpt:`

